#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int u, v, weight;
} Edge;

typedef struct {
    int parent, rank;
} DSU;

int compare(const void *a, const void *b) {
    return ((Edge*)a)->weight - ((Edge*)b)->weight;
}

int find(DSU *dsu, int x) {
    if (dsu[x].parent != x)
        dsu[x].parent = find(dsu, dsu[x].parent); // Path compression
    return dsu[x].parent;
}

void unionSets(DSU *dsu, int x, int y) {
    int rootX = find(dsu, x);
    int rootY = find(dsu, y);

    if (rootX != rootY) {
        if (dsu[rootX].rank < dsu[rootY].rank) {
            dsu[rootX].parent = rootY;
        } else if (dsu[rootX].rank > dsu[rootY].rank) {
            dsu[rootY].parent = rootX;
        } else {
            dsu[rootY].parent = rootX;
            dsu[rootX].rank++;
        }
    }
}

void kruskal(Edge edges[], int V, int E) {
    qsort(edges, E, sizeof(Edge), compare);

    DSU dsu[V];
    for (int i = 0; i < V; i++) {
        dsu[i].parent = i;
        dsu[i].rank = 0;
    }

    int mstWeight = 0, edgeCount = 0;

    for (int i = 0; i < E && edgeCount < V - 1; i++) {
        int u = edges[i].u;
        int v = edges[i].v;

        if (find(dsu, u) != find(dsu, v)) {
            unionSets(dsu, u, v);
            printf("Edge %d-%d: %d\n", u, v, edges[i].weight);
            mstWeight += edges[i].weight;
            edgeCount++;
        }
    }

    printf("Total MST Weight: %d\n", mstWeight);
}

int main() {
    int V = 5, E = 7;
    Edge edges[] = {{0,1,2}, {1,2,3}, {0,3,6}, {3,4,4}, {4,2,1}, {1,3,5}, {2,4,7}};
    kruskal(edges, V, E);
    return 0;
}
